  5→export type TransactionGainType = 'CARD' | 'TAG' | 'CASHBACK';
  6→
  7→export const getTransactionGainType = (
  8→  transaction: MyOrdersDetailProps['transaction'],
  9→): TransactionGainType => {
 10→  if (!transaction) return 'CARD';
 11→
 12→  const provider = transaction.details?.provider?.toLowerCase() || '';
 13→
 14→  if (provider.includes('cashback')) {
 15→    return 'CASHBACK';
 16→  }
 17→
 18→  const icon = transaction.icon?.toLowerCase() || '';
 19→  const description = transaction.description?.toLowerCase() || '';
 20→
 21→  const tagIndicators = [
 22→    'tag',
 23→    'pedágio',
 24→    'pedagio',
 25→    'estacionamento',
 26→    'abastecimento',
 27→    'abastece',
 28→    'drive',
 29→    'lava',
 30→    'rápido',
 31→  ];
 32→
 33→  const isTag = tagIndicators.some(
 34→    indicator =>
 35→      icon.includes(indicator) ||
 36→      description.includes(indicator) ||
 37→      provider.includes(indicator),
 38→  );
 39→
 40→  return isTag ? 'TAG' : 'CARD';
 41→};
