 43→export const getFormattedPointsValue = (
 44→  amount: number,
 45→  type: TransactionType,
 46→): string => {
 47→  const prefix = type === 'CREDIT' || type === 'REFUNDED' ? '+ ' : '- ';
 48→  const label = Math.abs(amount) === 1 ? 'ponto' : 'pontos';
 49→  return `${prefix}${Math.abs(amount).toLocaleString('pt-BR')} ${label}`;
 50→};
 51→
 52→export const getFormattedHighlightText = (
 53→  date: string,
 54→  _gainType: TransactionGainType,
 55→  momentInstance: typeof moment,
 56→): string => {
 57→  const transactionDate = momentInstance(date);
 58→  const day = transactionDate.format('DD');
 59→  const month = transactionDate.format('MMM').toLowerCase();
 60→  const year = transactionDate.format('YYYY');
 61→  const time = transactionDate.format('HH:mm');
 62→
 63→  return `Pedido feito em ${day} ${month} ${year} às ${time}`;
 64→};
