 83→export const getMarketplaceTitle = (
 84→  transaction: MyOrdersDetailProps['transaction'],
 85→): string | null => {
 86→  if (!transaction?.marketplace?.orders) return null;
 87→
 88→  const allItems: Array<{ name: string }> = [];
 89→  transaction.marketplace.orders.forEach(order => {
 90→    if (order.items) {
 91→      allItems.push(...order.items);
 92→    }
 93→  });
 94→
 95→  if (allItems.length === 0) return null;
 96→  if (allItems.length === 1) return allItems[0].name;
 97→
 98→  const firstItemName = allItems[0].name;
 99→  const secondItemFirstWord = allItems[1].name.split(' ')[0];
100→
101→  if (allItems.length === 2) {
102→    return `${firstItemName} e ${secondItemFirstWord}`;
103→  }
104→
105→  const remainingCount = allItems.length - 2;
106→  return `${firstItemName}, ${secondItemFirstWord} e outros ${remainingCount}`;
107→};
