109→export const getAdditionalFields = (
110→  transaction: PointsTransaction,
111→): Array<{ label: string; value: string }> => {
112→  const fields = transaction.details?.fields || [];
113→  const extractedLabels = ['marca', 'modelo', 'placa', 'origem', 'origin'];
114→
115→  return fields.filter(f => {
116→    const label = f.label?.toLowerCase() || '';
117→    return (
118→      label &&
119→      f.value &&
120→      !extractedLabels.some(extracted => label.includes(extracted))
121→    );
122→  });
123→};
