125→export const getCleanedImageUrl = (
126→  url: string | undefined,
127→): string | undefined => {
128→  if (!url) return undefined;
129→
130→  let cleanedUrl = url.trim();
131→
132→  if (cleanedUrl.startsWith('imageUrl:')) {
133→    cleanedUrl = cleanedUrl.replace(/^imageUrl:/i, '');
134→  }
135→
136→  if (cleanedUrl.startsWith('http://') || cleanedUrl.startsWith('https://')) {
137→    return cleanedUrl;
138→  }
139→
140→  return undefined;
141→};
